running: bool = True
offset: int = 600
stop_event: Event = Event()
frequencies: list[str] = ["1 min", "5 min", "10 min", "15 min", "20 min", "30 min", "1 hour"]
selected_frequency: str = frequencies[0]

def play_sound(sound: Sound):
    sound.play()
    stop_event.wait(sound.get_length())

def quit() -> None:
    global running
    running = False
    stop_event.set()


def resource_path(relative_path: str) -> str:
    import sys
    base_path = getattr(sys, '_MEIPASS', path.dirname(path.abspath(__file__)))
    return path.join(base_path, relative_path)

def set_active_freq(icon, item: MenuItem, frequency_str: str) -> None:
    global selected_frequency
    selected_frequency = frequency_str
        
    frequency_select()
    stop_event.set()



def frequency_select() -> None:
    global offset
    global frequencies
    global selected_frequency
    
    match selected_frequency: # it had to be done this bs f if f == way because python doesnt allow indexing in cases
        case f if f == frequencies[0]:
            offset = 60
        case f if f == frequencies[1]:
            offset = 300
        case f if f == frequencies[2]:
            offset = 600
        case f if f == frequencies[3]:
            offset = 900
        case f if f == frequencies[4]:
            offset = 1200
        case f if f == frequencies[5]:
            offset = 1800
        case f if f == frequencies[6]:
            offset = 3600
        case _:
            print("ERROR in selecting frequency")
            return
        
    
# i typed half the stuff and didnt type the other because pystray has wonderful typing...
# i also get that maybe its stupid to init pygame's audio mixer just for playing sounds but i really
# couldnt figure out anything else that also works well with stupid pyinstaller
if __name__ == "__main__":
    init()
    
    icon: ImageFile = Image.open(resource_path("icon.ico"))
    
    
    # the * is needed to 'unpack' the list (pystray doesnt accept raw lists for some reason)
    frequency: Menu = Menu(*[
        MenuItem(
            frequencies[i], 
            partial(set_active_freq, frequency_str=frequencies[i]),
            checked=lambda item, freq=frequencies[i]: freq == selected_frequency,
        )
        for i in range(len(frequencies))
    ])
    
    frequency_parent: MenuItem = MenuItem("Select frequency", frequency)
    title_item: MenuItem = MenuItem("Chirpware v1.0", None, enabled=False)
    menu: Menu = Menu(title_item, Menu.SEPARATOR, frequency_parent, MenuItem("Quit", quit))
    app = Icon("Chirpware", icon, "Chirpware", menu)
    
    app.run_detached() # type: ignore
    sound: Sound = Sound(BytesIO(AUDIO_DATA))
    
    frequency_select()
    
    while running:
        while not stop_event.is_set():
            print(offset * 0.9 + (offset * 0.1 * random()))
            stop_event.wait(offset * 0.9 + (offset * 0.1 * random()))
            play_sound(sound)
        stop_event.clear()
    app.stop()
        
